var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"자, 약속한 대로야. 네가 준비한 명의로 시장에 나온 퓨처 앳 워의 지분을 모두 사들였어.","JPN":"さあ、約束したとおりよ。あんたが用意した名義で市場に出されたフューチャーアットウォーの株をすべて買収したわ。","ENG":"Here, as promised. I bought all of the Future-at-War stocks in the market with the account you gave me.","TWN":"按照約定，我已經用你準備的身分，買下天啟兵器在市面上所有的股份，"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"이제 우리 회사는 퓨처 앳 워 재단의 최대 주주야.","JPN":"もう我が社はフューチャーアットウォー財団の筆頭株主よ。","ENG":"Now, we are the majority shareholder of the Future-at-War Foundation.","TWN":"現在我們公司是天啟兵器財團的最大股東！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"덕분에 회사가 보유한 현금을 거의 다 써버렸지만.","JPN":"おかげで会社が保有していた現金をほとんど使い果たしてしまったけどね。","ENG":"Although, thanks to that, we used up all of the company’s cash reserve.","TWN":"不過也因為這樣，公司所有的現金幾乎花得一毛不剩。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"어때? 돈지랄을 한 기념으로 샴페인이나 터뜨려 볼까?","JPN":"どう？　財産を使い果たした記念にシャンパンでも開ける？","ENG":"So? How about we pop open a bottle of champagne in celebration?","TWN":"如何？要開個香檳慶祝一下把錢花光光嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"샴페인이라…… 좋은 생각이군.","JPN":"シャンパンか……いい考えだ。","ENG":"Champagne, eh? Great idea.","TWN":"香檳嗎……這個點子不錯。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"수고했네, <color=#ffd34c>갬블러</color>. 자네 덕분에 세상의 흐름을 다시 한 번 바꿀 수 있게 됐어.","JPN":"ご苦労だった、<color=#ffd34c>ギャンブラー</color>。君のおかげで世界の流れを\\nもう一度変えられるようになったよ。","ENG":"Good job, <color=#ffd34c>Gambler</color>. Thanks to you, we can change the flow of the world once again.","TWN":"辛苦你了，<color=#ffd34c>賭徒</color>。托你的福，才能再次改變世界的潮流。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"세상의 흐름……? 언제나처럼 무슨 소릴 하는지 모를 녀석이군.","JPN":"世界の流れ……？　いつものことだけど、ほんと何言ってるのか\\nわからないやつね。","ENG":"The flow of the world...? As usual, I have no idea what you’re talking about.","TWN":"世界的潮流……？你還是一如往常地講些我聽不懂的話。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그런데 왜 갑자기 내게 퓨처 앳 워 재단을 인수하라고 한 거지?","JPN":"ところで、どうして急にフューチャーアットウォー財団を買収しろなんて言ったの？","ENG":"Hey Sysop, why did you ask me to buy all those shares of Future-at-War?","TWN":"不過為什麼突然要我收購天啟兵器財團？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"기술력은 뛰어나지만 하나같이 채산성이 부족한 것들 뿐이잖아, 시솝.","JPN":"技術力は優れているけど、採算性に乏しいものばかりじゃない、シソップ？","ENG":"I know their technology is great and all, but most of it can’t even turn a profit.","TWN":"他們的技術確實很不錯，可是一樣利潤不佳不是嗎，錫索普？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"뭔가 좋은 정보라도 들어온 건가?","JPN":"何かいい情報でも入ってきたの？","ENG":"Did someone give you the inside scoop or something?","TWN":"還是你有得到什麼內線消息？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"아니, 그저 <color=#ffd34c>새로운 친구</color>를 위한 환영 선물이 필요했을 뿐이야.","JPN":"いや、ただ<color=#ffd34c>新たな仲間</color>のための歓迎プレゼントが必要だっただけだ。","ENG":"No. I just needed a welcoming present for my <color=#ffd34c>new friend</color>.","TWN":"沒有，只是需要為<color=#ffd34c>新朋友</color>準備禮物而已。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워 재단에서 동결한 비밀 기술을 오랫동안 찾아다니던 친구거든.","JPN":"彼女はフューチャーアットウォー財団で凍結した秘密技術を、\\n長い間探していたからな。","ENG":"She has been looking for some secret technology that Future-at-War has put on hold for a long time.","TWN":"他一直在找天啟兵器藏起來的秘密技術。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"새로운 친구?","JPN":"新たな仲間？","ENG":"New friend?","TWN":"新朋友？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"이봐, 예전부터 말해주고 싶었는데 넌 좀 친구를 가려 사귈 필요가 있어.","JPN":"ねえ、前から言おうと思ってたけど、仲間はもう少し慎重に\\n選んだほうがいいわよ。","ENG":"You know, I’ve been meaning to tell you, but you really need to make some better friends.","TWN":"喂，我從以前就很想跟你說，拜託你交朋友的時候也挑一下吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그 성냥팔이란 녀석이나 헤이븐이나……","JPN":"あのマッチ売りとかいうのもそうだし、ヘイブンだって……","ENG":"Like that Matchmaker or Haven...","TWN":"那個什麼賣火柴的，還有什麼天堂的……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAMBLER_NPC_ALPHA_NULL","text":{"KOREA":"그런 떨거지들을 다 친구로 받아주면 세상이 우릴 우습게 여기게 된다고.","JPN":"あんな小者どもまで仲間として受け入れてたら、周りから舐められるわよ。","ENG":"If you make friends with those losers, you’ll be the laughingstock of the whole world.","TWN":"你跟那種下三濫交朋友，人家會瞧不起我們的！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하, 타인에 대한 자네의 평가 기준은 언제나 엄격하군.","JPN":"はは、他人に対する君の評価は相変わらず厳しいな。","ENG":"Haha. Your standards for judging others are always so strict.","TWN":"哈哈，你對別人的標準總是很嚴苛呢！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"GAMBLER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};